import Box from '@mui/material/Box';
import Carousel from 'react-material-ui-carousel';
import * as styles from './index.module.css';
import * as React from 'react';
import {graphql, useStaticQuery} from 'gatsby';
import SimpleVideo from './video';


const Media=({url,title})=>{
  const isVideo = url.endsWith('.mp4');
  if (isVideo) {
    return (<SimpleVideo src={url}></SimpleVideo>);
  }
  return (<img loading="lazy"  className={styles.carouselImage}
               width="100%" alt=""
               src={url}/>);


}
const BigCarousel = () => {
  const {
    allStrapiBanner,
  } = useStaticQuery(graphql`
  query BannerQuery {
  allStrapiBanner {
    nodes {
      image {
        localFile {
        publicURL
          childImageSharp {
            gatsbyImageData
          }
        }
      }
      title
      id
    }
  }
}`);
  return (<Box>
    <Carousel className={styles.carousel}
              animation="slide"
              navButtonsAlwaysVisible={false}
              navButtonsAlwaysInvisible={true}
              indicators={false}>
      {allStrapiBanner?.nodes?.map((item, i) => {
        return <Media url={item.image?.localFile?.publicURL}></Media>

      })}
    </Carousel>
  </Box>);
};

export default BigCarousel;
