const PageLink = ({page}) => {
  const [anchorEl, setAnchorEl] = React.useState(null);
  const open = Boolean(anchorEl);
  const handleClick = (event) => {
    setAnchorEl(event.currentTarget);
  };
  const handleClose = () => {
    setAnchorEl(null);
  };
  return (
      <>
        <ButtonGroup  variant="text" disableElevation aria-label="split button">
          <Button sx={{borderRight:'none'}} disableElevation
                  onMouseOver={handleClick}
          >{page?.text}</Button>
          {page.items&&page.items.length&& <Button
              size="small"
              aria-controls={open ? 'split-button-menu' : undefined}
              aria-expanded={open ? 'true' : undefined}
              aria-label="select merge strategy"
              aria-haspopup="menu"
              onClick={handleClick}
          >
            <ArrowDropDownIcon/>
          </Button>}
        </ButtonGroup>
        <StyledMenu
            anchorEl={anchorEl}
            open={open}
            onClose={handleClose}
        >
          {page?.items?.map((item, index) => {
            return (<MenuItem href={item.url} disableRipple>
              {item.text}
            </MenuItem>);

          })}
        </StyledMenu>
      </>
  );

};

