/**
 * Layout component that queries for data
 * with Gatsby's useStaticQuery component
 *
 * See: https://www.gatsbyjs.com/docs/how-to/querying-data/use-static-query/
 */

import * as React from 'react';
import {graphql, useStaticQuery} from 'gatsby';
import Header from './header';
import BigCarousel from './banner';
import Footer from './footer';
import Box from '@mui/material/Box';
import theme from './../theme';
import {ThemeProvider} from '@mui/material/styles';
import CssBaseline from '@mui/material/CssBaseline';
import InventoryIcon from '@mui/icons-material/Inventory';
import InsertPhotoIcon from '@mui/icons-material/InsertPhoto';
import FeedIcon from '@mui/icons-material/Feed';
import PublicIcon from '@mui/icons-material/Public';
import InfoIcon from '@mui/icons-material/Info';
import './layout.css';

const Layout = ({children}) => {
  const {allStrapiProductType} = useStaticQuery(
      graphql`
  query LayoutQuery {
  allStrapiProductType {
    nodes {
      id
      name
    }
  }
}
`);
  const items = allStrapiProductType.nodes.map(
      item => ({text: item.name, url: `/product/${item.id}`}));
  const pages = [
    {text: '首页', url: '/', icon: () => <FeedIcon/>},
    {
      text: '产品中心',
      url: '/product',
      icon: () => <InventoryIcon/>,
      items,
    },
    {text: '新闻资讯', url: '/news', icon: () => <FeedIcon/>},
    {text: '联系方式', url: '/contact', icon: () => <PublicIcon/>},
    {
      text: '关于我们', url: '/about', icon: () => <InfoIcon/>,
    },
  ];
  return (
      <ThemeProvider theme={theme}>
        <CssBaseline/>
        <Header pages={pages}/>

        <Box component="main">
          <BigCarousel></BigCarousel>
          {children}
        </Box>
        <Footer pages={pages}/>
      </ThemeProvider>

  );
};

export default Layout;
